 const phase = ((((new Date() - new Date('2024-01-11'))/86400000) % 29.53) + 29.53) % 29.53;
 const icons = ['🌑','🌒','🌓','🌔','🌕','🌖','🌗','🌘'];
 const names = ['അമാവാസി','വളരുന്ന','ഒന്നാം ചതുർഥി','വളരുന്ന','പൗർണ്ണമി','കുറയുന്ന','മൂന്നാം ചതുർഥി','കുറയുന്ന'];
 const idx = Math.round(phase/29.53*8) % 8;
